drop extension if exists "pg_net";


  create table "public"."beats" (
    "id" integer generated by default as identity not null,
    "beat" text not null,
    "beat_short" text,
    "river_order" text,
    "upper_lower" text
      );


alter table "public"."beats" enable row level security;


  create table "public"."catch_returns" (
    "id" integer generated by default as identity not null,
    "member_name" text,
    "catch_date" date,
    "brown_trout" integer,
    "brown_trout_killed" integer,
    "grayling" integer,
    "rainbow_trout" integer,
    "other_species" integer,
    "guest" boolean,
    "beats_id" integer,
    "dnf" boolean default false
      );


alter table "public"."catch_returns" enable row level security;


  create table "public"."catch_returns_staging_table" (
    "id" integer generated by default as identity not null,
    "timestamp" text,
    "rod_name" text,
    "catch_date" date,
    "beat" text,
    "brown_trout_released" integer,
    "grayling" integer,
    "rainbow_trout" integer,
    "other_species" integer,
    "brown_trout_retained" integer,
    "guest" boolean,
    "comments" text,
    "dnf" boolean default false
      );


alter table "public"."catch_returns_staging_table" enable row level security;


  create table "public"."members" (
    "id" integer generated by default as identity not null,
    "cr_name" text,
    "email_address" text,
    "member_name" text,
    "year_of_membership" integer
      );


alter table "public"."members" enable row level security;


  create table "public"."reservation_beats" (
    "id" bigint generated by default as identity not null,
    "beat" text not null,
    "beat_id" bigint
      );


alter table "public"."reservation_beats" enable row level security;


  create table "public"."reservations_confirmed_staging" (
    "id" bigint generated by default as identity not null,
    "date" date not null,
    "resource" text not null,
    "name" text not null,
    "cr_name" text
      );


alter table "public"."reservations_confirmed_staging" enable row level security;


  create table "public"."year_param" (
    "id" integer generated by default as identity not null,
    "target_year" integer,
    "target_start_date" date,
    "target_end_date" date
      );


CREATE UNIQUE INDEX "CatchReturns_pkey" ON public.catch_returns USING btree (id);

CREATE UNIQUE INDEX beats_pkey ON public.beats USING btree (id);

CREATE UNIQUE INDEX catch_returns_staging_table_pkey ON public.catch_returns_staging_table USING btree (id);

CREATE INDEX idx_beat ON public.catch_returns_staging_table USING btree (beat);

CREATE INDEX idx_beats_beat ON public.beats USING btree (beat);

CREATE INDEX idx_beats_river_order ON public.beats USING btree (river_order);

CREATE INDEX idx_beats_upper_lower ON public.beats USING btree (upper_lower);

CREATE INDEX idx_catch_date ON public.catch_returns_staging_table USING btree (catch_date);

CREATE INDEX idx_catch_returns_beats_id ON public.catch_returns USING btree (beats_id);

CREATE INDEX idx_catch_returns_catch_date ON public.catch_returns USING btree (catch_date);

CREATE INDEX idx_catch_returns_guest ON public.catch_returns USING btree (guest);

CREATE INDEX idx_reservation_beats_beat ON public.reservation_beats USING btree (beat);

