CREATE UNIQUE INDEX members_pkey ON public.members USING btree (id);

CREATE INDEX members_year_of_membership_idx ON public.members USING btree (year_of_membership);

CREATE UNIQUE INDEX reservation_beats_pkey ON public.reservation_beats USING btree (id);

CREATE UNIQUE INDEX reservations_confirmed_staging_pkey ON public.reservations_confirmed_staging USING btree (id);

CREATE UNIQUE INDEX year_param_pkey ON public.year_param USING btree (id);

alter table "public"."beats" add constraint "beats_pkey" PRIMARY KEY using index "beats_pkey";

alter table "public"."catch_returns" add constraint "CatchReturns_pkey" PRIMARY KEY using index "CatchReturns_pkey";

alter table "public"."catch_returns_staging_table" add constraint "catch_returns_staging_table_pkey" PRIMARY KEY using index "catch_returns_staging_table_pkey";

alter table "public"."members" add constraint "members_pkey" PRIMARY KEY using index "members_pkey";

alter table "public"."reservation_beats" add constraint "reservation_beats_pkey" PRIMARY KEY using index "reservation_beats_pkey";

alter table "public"."reservations_confirmed_staging" add constraint "reservations_confirmed_staging_pkey" PRIMARY KEY using index "reservations_confirmed_staging_pkey";

alter table "public"."year_param" add constraint "year_param_pkey" PRIMARY KEY using index "year_param_pkey";

set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$
;

create or replace view "public"."table_indexes_non_pk" as  SELECT schemaname AS schema_name,
    tablename AS table_name,
    indexname AS index_name,
    indexdef AS index_definition
   FROM pg_indexes
  WHERE ((schemaname = 'public'::name) AND (NOT (indexname IN ( SELECT pg_constraint.conname
           FROM pg_constraint
          WHERE (pg_constraint.contype = 'p'::"char")))))
  ORDER BY tablename, indexname;


create or replace view "public"."table_policies_overview" as  SELECT schemaname,
    tablename,
    policyname,
    permissive,
    roles,
    cmd,
    qual,
    with_check
   FROM pg_policies
  ORDER BY tablename;


create or replace view "public"."table_rls_overview" as  SELECT pg_class.relname AS table_name,
        CASE
            WHEN (pg_class.relrowsecurity = true) THEN '✅ ENABLED (Locked)'::text
            ELSE '⚠️ DISABLED (Open)'::text
        END AS rls_status
   FROM (pg_class
     JOIN pg_namespace ON ((pg_namespace.oid = pg_class.relnamespace)))
  WHERE ((pg_namespace.nspname = 'public'::name) AND (pg_class.relkind = 'r'::"char"))
  ORDER BY pg_class.relname;


create or replace view "public"."view_reservations_confirmed_staging" as  SELECT rcs.date,
    rcs.cr_name,
    rb.beat_id,
    bt.beat
   FROM ((public.reservations_confirmed_staging rcs
     JOIN public.reservation_beats rb ON ((rb.beat = rcs.resource)))
     JOIN public.beats bt ON ((rb.beat_id = bt.id)))
  ORDER BY rcs.date;


create or replace view "public"."view_catch_returns_missing" as  SELECT date,
    cr_name,
    beat_id,
    beat,
    floor(EXTRACT(day FROM (CURRENT_TIMESTAMP - ((date)::timestamp without time zone)::timestamp with time zone))) AS full_days_elapsed
   FROM public.view_reservations_confirmed_staging vrcs
  WHERE ((date < CURRENT_DATE) AND (NOT (EXISTS ( SELECT 1
           FROM public.catch_returns_staging_table crst
          WHERE ((vrcs.date = crst.catch_date) AND (vrcs.beat = crst.beat) AND (vrcs.cr_name = crst.rod_name))))))
  ORDER BY (floor(EXTRACT(day FROM (CURRENT_TIMESTAMP - ((date)::timestamp without time zone)::timestamp with time zone)))) DESC;


create or replace view "public"."view_missing_cr_age_report" as  
WITH return_stats AS (
    SELECT 
        vrcs.cr_name,
        CURRENT_DATE - vrcs.date AS days_old,
        -- 1 if submitted, 0 if missing
        CASE WHEN crst.rod_name IS NOT NULL THEN 1 ELSE 0 END as was_submitted
    FROM view_reservations_confirmed_staging vrcs
    LEFT JOIN catch_returns_staging_table crst 
        ON vrcs.cr_name = crst.rod_name 
        AND vrcs.date = crst.catch_date
    WHERE vrcs.date < CURRENT_DATE
)
SELECT 
    m.member_name,
    SUM(rs.was_submitted) AS "Returns Submitted",
    --COUNT(CASE WHEN rs.was_submitted = 0 AND rs.days_old <= 7 THEN 1 END) AS "1-7 Days",
    COUNT(CASE WHEN rs.was_submitted = 0 AND rs.days_old > 7 AND rs.days_old <= 14 THEN 1 END) AS "8-14 Days",
    COUNT(CASE WHEN rs.was_submitted = 0 AND rs.days_old > 14 AND rs.days_old <= 21 THEN 1 END) AS "15-21 Days",
    COUNT(CASE WHEN rs.was_submitted = 0 AND rs.days_old > 21 AND rs.days_old <= 28 THEN 1 END) AS "21-28 Days",
    COUNT(CASE WHEN rs.was_submitted = 0 AND rs.days_old > 28 THEN 1 END) AS "28+ Days",
    COUNT(CASE WHEN rs.was_submitted = 0 THEN 1 END) AS "Total Missing"
FROM members m
JOIN return_stats rs ON m.cr_name = rs.cr_name
GROUP BY m.member_name
-- Filter: Only show members where the count of missing returns is greater than 0
HAVING COUNT(CASE WHEN rs.was_submitted = 0 THEN 1 END) > 0
ORDER BY "Total Missing" DESC;

